INSERT INTO `pet` (`name`, `type`, `breed`, `age`, `gender`, `size`, `color`, `weight`, `vaccinated`, `neutered`, `health_desc`, `personality`, `requirement`, `images`, `status`) VALUES
('旺财', '狗', '金毛寻回犬', 24, '公', '大型', '金色', 28.50, 1, 1, '身体健康，已完成全部疫苗接种，已绝育。定期驱虫，无任何遗传疾病。', '性格温顺友好，喜欢亲近人类，对小朋友特别有耐心。喜欢户外运动，擅长捡球游戏。', '需要有足够的活动空间，每天需要1-2小时户外运动时间。适合有养狗经验的家庭。', 'https://plus.unsplash.com/premium_photo-1666777247416-ee7a95235559?w=800&auto=format&fit=crop&q=60,https://images.unsplash.com/photo-1552053831-71594a27632d?w=800&auto=format&fit=crop&q=60', 1),
('Lucky', '狗', '拉布拉多', 18, '公', '大型', '黑色', 30.20, 1, 1, '健康状况良好，疫苗齐全，已做绝育手术。视力听力正常，关节健康。', '活泼好动，智商高，容易训练。对主人忠诚，喜欢游泳和户外活动。', '需要大量运动，适合有院子的家庭。需要主人有足够时间陪伴。', 'https://images.unsplash.com/photo-1530281700549-e82e7bf110d6?w=800&auto=format&fit=crop&q=60', 1),
('豆豆', '狗', '柴犬', 12, '母', '中型', '赤色', 9.80, 1, 0, '身体健康，已完成基础疫苗接种。定期体检，各项指标正常。', '性格独立倔强但很可爱，表情丰富。喜欢散步，对陌生人有警惕性。', '需要耐心训练，适合有柴犬饲养经验的领养者。需要定期梳理毛发。', 'https://images.unsplash.com/photo-1543466835-00a7907e9de1?w=800&auto=format&fit=crop&q=60,https://images.unsplash.com/photo-1518020382113-a7e8fc38eac9?w=800&auto=format&fit=crop&q=60', 1),
('二哈', '狗', '哈士奇', 36, '公', '大型', '黑白', 25.00, 1, 1, '健康活泼，骨骼发育良好。疫苗完整，已绝育。眼睛为蓝色，非常漂亮。', '精力充沛，性格活泼，喜欢拆家。需要大量运动消耗精力。对人友好但较为调皮。', '需要有足够的活动空间和运动量。建议有养大型犬经验的家庭领养。', 'https://images.unsplash.com/photo-1561037404-61cd46aa615b?w=800&auto=format&fit=crop&q=60', 1),
('雪球', '狗', '萨摩耶', 8, '母', '大型', '白色', 20.00, 1, 0, '幼犬健康成长中，已完成首针疫苗。毛发浓密柔软，需要定期护理。', '性格温顺，喜欢微笑，是著名的"微笑天使"。对人类非常友好。', '需要每天梳毛，定期洗澡美容。适合有时间打理狗狗的家庭。', 'https://plus.unsplash.com/premium_photo-1694819488591-a43907d1c5cc?w=800&auto=format&fit=crop&q=60,https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=800&auto=format&fit=crop&q=60', 1),
('小柯', '狗', '柯基', 15, '公', '小型', '黄白', 12.50, 1, 1, '身体健康，四肢发育正常。已完成全部疫苗和绝育手术。', '性格开朗，喜欢跑跳。虽然腿短但非常活泼，喜欢和人互动。', '需要控制体重，避免脊椎问题。每天需要适量运动。', 'https://images.unsplash.com/photo-1534361960057-19889db9621e?w=800&auto=format&fit=crop&q=60', 1),
('泰迪', '狗', '泰迪', 6, '母', '小型', '棕色', 4.20, 1, 0, '幼犬健康可爱，正在接种疫苗中。毛发卷曲，需要定期修剪。', '聪明伶俐，容易训练。喜欢粘人，需要主人多陪伴。', '适合公寓饲养，需要定期美容护理。建议有养小型犬经验者领养。', 'https://plus.unsplash.com/premium_photo-1722859221349-26353eae4744?w=800&auto=format&fit=crop&q=60', 1),
('棉花糖', '狗', '比熊', 24, '母', '小型', '白色', 5.50, 1, 1, '健康状况优秀，毛发雪白蓬松。已完成所有疫苗和绝育。', '性格温和，喜欢被抱着。不掉毛，适合对毛发过敏的人。', '需要定期美容修剪，保持造型。适合陪伴型养宠需求。', 'https://images.unsplash.com/photo-1596492784531-6e6eb5ea9993?w=800&auto=format&fit=crop&q=60', 1),
('法斗', '狗', '法国斗牛犬', 30, '公', '中型', '虎斑', 13.00, 1, 1, '身体健康，呼吸系统正常。已完成疫苗接种和绝育。', '性格安静，不爱叫。喜欢宅在家里，是很好的伴侣犬。', '注意避免剧烈运动和高温环境。适合公寓饲养。', 'https://images.unsplash.com/photo-1537151625747-768eb6cf92b2?w=800&auto=format&fit=crop&q=60', 1),
('巴哥', '狗', '巴哥犬', 48, '公', '小型', '杏色', 8.00, 1, 1, '成年犬，身体状况良好。面部皱纹需要定期清理。已绝育。', '性格憨厚可爱，表情丰富。喜欢安静，适合老年人陪伴。', '注意皮肤护理，避免过热。每天需要短距离散步。', 'https://images.unsplash.com/photo-1517849845537-4d257902454a?w=800&auto=format&fit=crop&q=60', 1),
('大毛', '狗', '阿拉斯加', 20, '公', '大型', '黑白', 45.00, 1, 1, '大型犬健康状况良好，骨骼发育完善。已完成全部疫苗。', '温和友善的巨型犬，虽然体型大但性格温顺。喜欢寒冷天气。', '需要大量空间和运动。食量大，需要有足够的经济能力。', 'https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=800&auto=format&fit=crop&q=60', 1),
('来福', '狗', '中华田园犬', 36, '公', '中型', '黄色', 18.00, 1, 1, '身体素质好，抗病能力强。本土犬种，适应性强。', '忠诚护主，聪明机警。对家人温顺，对陌生人警惕。', '适合有院子的家庭。需要基本训练和社会化。', 'https://images.unsplash.com/photo-1504826260979-242151ee45b7?w=800&auto=format&fit=crop&q=60', 1),
('贝贝', '狗', '博美', 10, '母', '小型', '白色', 3.20, 1, 0, '小型犬健康活泼，毛发蓬松需要护理。正在完成疫苗接种。', '活泼好动，喜欢叫。对主人忠诚，有较强的领地意识。', '需要定期梳理毛发。注意训练减少吠叫行为。', 'https://images.unsplash.com/photo-1503256207526-0d5d80fa2f47?w=800&auto=format&fit=crop&q=60', 1),
('雪瑞', '狗', '雪纳瑞', 18, '公', '中型', '椒盐色', 8.50, 1, 1, '身体健康，胡子造型独特。已完成疫苗和绝育。不易掉毛。', '聪明勇敢，有较强的看家本领。对家人友好，对陌生人警惕。', '需要定期修剪胡子造型。需要适量运动。', 'https://plus.unsplash.com/premium_photo-1666229410352-c4686b71cea2?w=800&auto=format&fit=crop&q=60', 1),
('小黑', '狗', '拉布拉多', 24, '母', '大型', '黑色', 26.00, 1, 1, '成年母犬，性格沉稳。健康状况良好，已完成绝育。', '性格温和稳重，不像年轻拉布拉多那么闹。很适合家庭。', '需要每天运动，但运动量比幼犬少。适合有小孩的家庭。', 'https://images.unsplash.com/photo-1588943211346-0908a1fb0b01?w=800&auto=format&fit=crop&q=60', 1),
('花花', '狗', '边境牧羊犬', 14, '母', '中型', '黑白', 16.00, 1, 0, '智商最高的犬种之一，身体健康活泼。疫苗接种中。', '极其聪明，学习能力强。精力旺盛，需要大量运动和智力游戏。', '需要有经验的主人进行训练。每天需要2小时以上运动。', 'https://images.unsplash.com/photo-1510771463146-e89e6e86560e?w=800&auto=format&fit=crop&q=60', 1),

-- 猫 - 可领养状态
('咪咪', '猫', '英短蓝猫', 18, '母', '中型', '蓝灰色', 4.50, 1, 1, '英短标准体型，圆脸大眼睛。身体健康，已完成疫苗和绝育。', '性格安静温顺，不爱叫。喜欢独处但也接受抚摸。适应能力强。', '适合公寓饲养，需要定期梳毛。不需要太多运动。', 'https://plus.unsplash.com/premium_photo-1667030474693-6d0632f97029?w=800&auto=format&fit=crop&q=60,https://images.unsplash.com/photo-1495360010541-f48722b34f7d?w=800&auto=format&fit=crop&q=60', 1),
('虎斑', '猫', '美短虎斑', 24, '公', '中型', '银虎斑', 5.20, 1, 1, '经典美短虎斑纹路，身材匀称。健康状况良好。', '活泼好动，喜欢玩耍。性格友好，能与其他宠物相处。', '需要玩具和猫爬架。每天需要一定的互动时间。', 'https://images.unsplash.com/photo-1519052537078-e6302a4968d4?w=800&auto=format&fit=crop&q=60,https://images.unsplash.com/photo-1573865526739-10659fec78a5?w=800&auto=format&fit=crop&q=60', 1),
('布丁', '猫', '布偶猫', 12, '母', '大型', '海双色', 4.80, 1, 0, '布偶猫幼猫，蓝眼睛，毛色正在发育中。健康活泼。', '性格温顺如布偶，喜欢被抱着。对人非常亲近和依赖。', '需要定期梳毛防止打结。需要较多陪伴时间。', 'https://plus.unsplash.com/premium_photo-1707353401897-da9ba223f807?w=800&auto=format&fit=crop&q=60', 1),
('波斯', '猫', '波斯猫', 36, '母', '中型', '白色', 4.00, 1, 1, '纯白波斯猫，扁脸，长毛。需要每天梳毛护理。', '性格安静优雅，喜欢安静的环境。不太活跃，适合室内饲养。', '需要每天梳毛，定期清理眼睛。注意呼吸道健康。', 'https://images.unsplash.com/photo-1511044568932-338cba0ad803?w=800&auto=format&fit=crop&q=60', 1),
('暹罗', '猫', '暹罗猫', 20, '公', '中型', '海豹色', 4.20, 1, 1, '典型暹罗猫重点色，蓝眼睛。身材修长健康。', '性格活泼好动，喜欢叫。非常粘人，需要主人多陪伴互动。', '可能会比较吵，适合喜欢互动的主人。需要玩具消耗精力。', 'https://images.unsplash.com/photo-1472491235688-bdc81a63246e?w=800&auto=format&fit=crop&q=60', 1),
('大橘', '猫', '橘猫', 30, '公', '大型', '橘色', 7.50, 1, 1, '"十橘九胖"的典型代表，圆滚滚很可爱。已绝育控制体重。', '性格憨厚，贪吃好睡。不太活跃，喜欢晒太阳睡觉。', '需要控制食量避免过胖。适合想要安静伴侣的人。', 'https://images.unsplash.com/photo-1596854407944-bf87f6fdd49e?w=800&auto=format&fit=crop&q=60,https://images.unsplash.com/photo-1571566882372-1598d88abd90?w=800&auto=format&fit=crop&q=60', 1),
('小花', '猫', '三花猫', 15, '母', '小型', '三色', 3.50, 1, 0, '漂亮的三花猫，毛色分布均匀。健康活泼，正在完成疫苗。', '性格温和，有点小傲娇。喜欢高处观察，爱干净。', '需要猫爬架和高处空间。女生专属（三花猫基本都是母猫）。', 'https://images.unsplash.com/photo-1503777119540-ce54b422baff?w=800&auto=format&fit=crop&q=60', 1),
('奶牛', '猫', '奶牛猫', 24, '公', '中型', '黑白', 5.00, 1, 1, '黑白花纹像奶牛一样可爱。性格活泼，已完成绝育。', '精力旺盛，喜欢疯跑和玩耍。性格有点神经质但很可爱。', '需要足够的活动空间和玩具。可能会有些调皮。', 'https://images.unsplash.com/photo-1514888286974-6c03e2ca1dba?w=800&auto=format&fit=crop&q=60', 1),
('狸花', '猫', '狸花猫', 36, '公', '中型', '狸花纹', 5.50, 1, 1, '中国本土猫种，身体素质好。毛发有光泽，精神状态佳。', '聪明独立，有较强的捕猎本能。对主人忠诚。', '适合有一定养猫经验的人。需要玩具满足狩猎本能。', 'https://images.unsplash.com/photo-1574144611937-0df059b5ef3e?w=800&auto=format&fit=crop&q=60', 1),
('俄蓝', '猫', '俄罗斯蓝猫', 16, '母', '中型', '蓝灰色', 3.80, 1, 1, '优雅的俄罗斯蓝猫，绿眼睛，银色毛尖。低敏感性毛发。', '性格害羞安静，需要时间适应新环境。一旦熟悉会非常亲人。', '需要安静的环境，不适合有小孩的家庭。需要耐心。', 'https://images.unsplash.com/photo-1533738363-b7f9aef128ce?w=800&auto=format&fit=crop&q=60', 1),
('加菲', '猫', '加菲猫', 28, '公', '中型', '红虎斑', 6.00, 1, 1, '圆脸加菲猫，扁鼻子大眼睛。需要定期清理面部皱褶。', '性格温和慵懒，不太活跃。喜欢安静地陪伴主人。', '注意面部清洁和呼吸道健康。适合安静的家庭环境。', 'https://plus.unsplash.com/premium_photo-1677181729163-33e6b59d5c8f?w=800&auto=format&fit=crop&q=60', 1),
('银渐层', '猫', '英短蓝猫', 10, '母', '中型', '银渐层', 3.20, 1, 0, '漂亮的银渐层英短，绿眼睛。幼猫正在成长中。', '性格活泼好奇，喜欢探索。对人友好，容易亲近。', '需要安全的探索空间。正在完成疫苗接种。', 'https://images.unsplash.com/photo-1574158622682-e40e69881006?w=800&auto=format&fit=crop&q=60', 1),
('豹猫', '猫', '孟加拉豹猫', 22, '公', '大型', '豹纹', 6.50, 1, 1, '漂亮的豹纹花色，肌肉发达。需要大量运动和空间。', '野性十足但已驯化，非常活跃。喜欢跑跳和攀爬。', '需要大空间和多层猫爬架。不适合新手养猫人。', 'https://images.unsplash.com/photo-1478098711619-5ab0b478d6e6?w=800&auto=format&fit=crop&q=60', 1),
('缅因', '猫', '缅因猫', 24, '公', '大型', '棕虎斑', 9.00, 1, 1, '巨型猫，长毛，有狮子般的鬃毛。身体健康，性格温和。', '虽然体型大但性格温顺如狗。喜欢水，可以训练遛猫。', '需要大空间和高质量猫粮。食量较大。', 'https://images.unsplash.com/photo-1592194996308-7b43878e84a6?w=800&auto=format&fit=crop&q=60', 1),
('小白', '猫', '中华田园猫', 8, '母', '小型', '白色', 2.50, 1, 0, '纯白中华田园猫幼猫，非常可爱。健康活泼。', '好奇心强，喜欢玩耍。容易训练，适应能力强。', '适合新手养猫。需要完成剩余疫苗接种。', 'https://images.unsplash.com/photo-1561948955-570b270e7c36?w=800&auto=format&fit=crop&q=60', 1),
('折耳', '猫', '苏格兰折耳猫', 20, '母', '中型', '蓝白', 4.00, 1, 1, '可爱的折耳猫，耳朵向前折叠。需要注意关节健康。', '性格甜美温顺，喜欢安静。很少叫，适合公寓饲养。', '注意关节保健，避免过度运动。定期检查骨骼健康。', 'https://plus.unsplash.com/premium_photo-1664299749481-ac8dc8b49754?w=800&auto=format&fit=crop&q=60', 1),

