('小泰', '狗', '泰迪', 18, '公', '小型', '红棕色', 5.50, 1, 1, '标准泰迪体型，毛发卷曲需要定期修剪。', '聪明粘人，喜欢被抱着。不掉毛适合公寓。', '需要定期美容。喜欢和人互动。', 'https://plus.unsplash.com/premium_photo-1722859221349-26353eae4744?w=800&auto=format&fit=crop&q=60', 1),
('雪糕', '狗', '萨摩耶', 15, '母', '大型', '白色', 22.00, 1, 0, '微笑天使，毛发雪白蓬松。需要每天梳毛。', '性格温顺开朗，总是带着微笑。对人非常友好。', '需要每天梳毛，夏天注意防暑。', 'https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=800&auto=format&fit=crop&q=60', 1),
('小蓝', '猫', '俄罗斯蓝猫', 24, '公', '中型', '蓝灰色', 4.50, 1, 1, '典型俄蓝，绿眼睛银色毛尖。优雅安静。', '安静害羞，需要时间适应。适应后非常忠诚。', '需要安静环境，不适合嘈杂家庭。', 'https://images.unsplash.com/photo-1533738363-b7f9aef128ce?w=800&auto=format&fit=crop&q=60', 1),
('橘子', '猫', '橘猫', 18, '公', '大型', '橘白', 6.80, 1, 1, '圆滚滚的橘猫，已绝育控制体重。', '贪吃好睡，性格温和。适合想要安静伴侣的人。', '需要控制食量。每天需要互动时间。', 'https://images.unsplash.com/photo-1596854407944-bf87f6fdd49e?w=800&auto=format&fit=crop&q=60', 1),
('小虎', '猫', '美短虎斑', 10, '公', '中型', '棕虎斑', 3.80, 1, 0, '幼猫健康活泼，虎斑纹路清晰。', '好奇心强，喜欢探索。爱玩玩具。', '需要安全的活动空间。正在完成疫苗。', 'https://images.unsplash.com/photo-1573865526739-10659fec78a5?w=800&auto=format&fit=crop&q=60', 1),
('雪团', '猫', '布偶猫', 20, '母', '大型', '蓝双色', 5.50, 1, 1, '漂亮布偶猫，蓝眼睛，毛色纯正。', '温顺如布偶，喜欢被抱。对人非常依赖。', '需要每天梳毛，定期洗澡。', 'https://plus.unsplash.com/premium_photo-1707353401897-da9ba223f807?w=800&auto=format&fit=crop&q=60', 1),
('黑豆', '猫', '中华田园猫', 15, '公', '中型', '纯黑', 4.50, 1, 1, '纯黑田园猫，毛发有光泽。身体素质好。', '性格独立，会抓老鼠。对主人忠诚。', '适合有一定养猫经验的人。', 'https://images.unsplash.com/photo-1514888286974-6c03e2ca1dba?w=800&auto=format&fit=crop&q=60', 1),
('花卷', '猫', '狸花猫', 12, '母', '中型', '狸花纹', 3.50, 1, 0, '漂亮的狸花猫，斑纹对称。健康活泼。', '聪明伶俐，有狩猎本能。喜欢玩逗猫棒。', '需要玩具满足狩猎欲望。需要完成疫苗。', 'https://images.unsplash.com/photo-1574144611937-0df059b5ef3e?w=800&auto=format&fit=crop&q=60', 1),
('小馒头', '其他', '侏儒兔', 6, '母', '小型', '白棕', 1.00, 1, 0, '迷你小兔子，非常可爱。适合小空间。', '温顺乖巧，喜欢被抚摸。', '需要专用兔粮和干草。', 'https://images.unsplash.com/photo-1668791627301-23690de58952?w=800&auto=format&fit=crop&q=60', 1),
('团子', '其他', '龙猫', 18, '公', '中型', '米色', 0.55, 1, 0, '米色龙猫，毛发柔软。健康活泼。', '性格活泼，夜间活跃。喜欢跳跃。', '需要凉爽环境，定期沙浴。', 'https://plus.unsplash.com/premium_photo-1667155652672-f7a4983f842f?w=800&auto=format&fit=crop&q=60', 1),
('小灰', '其他', '仓鼠', 4, '母', '小型', '灰色', 0.04, 0, 0, '可爱的三线仓鼠，健康活泼。', '夜行性，喜欢跑轮。', '需要仓鼠笼和跑轮。注意温度。', 'https://images.unsplash.com/photo-1695510864636-38ff5ba5a945?w=800&auto=format&fit=crop&q=60', 1);

